"use client";

import * as React from "react";

import { cn } from "@/lib/utils";
import {
  useHydrated,
  useExperienceViewport,
  usePrefersReducedMotion,
} from "@/components/experience/experience-runtime";

export type StickyStoryChapter = {
  id: string;
  eyebrow?: string;
  title: string;
  body: string;
};

type StickyStoryProps = Omit<React.ComponentProps<"section">, "children"> & {
  chapterClassName?: string;
  chapters: StickyStoryChapter[];
  contentClassName?: string;
  renderVisual: (chapter: StickyStoryChapter, index: number) => React.ReactNode;
  stageClassName?: string;
  stickyTop?: number | string;
  visualClassName?: string;
  visualLabel: string;
  visualSide?: "left" | "right";
};

/**
 * A chapter narrative whose desktop visual is registered to the viewport and
 * never participates in document movement. Mobile renders each matching visual
 * inline so the story stays complete without sticky behavior.
 */
export function StickyStory({
  chapterClassName,
  chapters,
  contentClassName,
  renderVisual,
  stageClassName,
  stickyTop = 0,
  visualClassName,
  visualLabel,
  visualSide = "left",
  className,
  ...props
}: StickyStoryProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const [activeIndex, setActiveIndex] = React.useState(0);
  const hydrated = useHydrated();
  const viewport = useExperienceViewport();
  const desktop = viewport === "desktop";
  const prefersReducedMotion = usePrefersReducedMotion();

  React.useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const chapterNodes = root.querySelectorAll<HTMLElement>("[data-story-index]");
    if (chapterNodes.length === 0) return;
    // A chapter is active while it overlaps a thin band centered in the
    // viewport; the observer replaces per-scroll-frame rect loops entirely.
    const observer = new IntersectionObserver((entries) => {
      let closestIndex = -1;
      let closestDistance = Number.POSITIVE_INFINITY;
      entries.forEach((entry) => {
        if (!entry.isIntersecting) return;
        const bounds = entry.rootBounds;
        const bandCenter = bounds ? bounds.top + bounds.height / 2 : window.innerHeight / 2;
        const rect = entry.boundingClientRect;
        const distance = Math.abs(rect.top + rect.height / 2 - bandCenter);
        if (distance < closestDistance) {
          closestDistance = distance;
          closestIndex = Number((entry.target as HTMLElement).dataset.storyIndex ?? 0);
        }
      });
      if (closestIndex < 0) return;
      setActiveIndex((current) => current === closestIndex ? current : closestIndex);
    }, { rootMargin: "-45% 0px -45% 0px" });
    chapterNodes.forEach((node) => observer.observe(node));
    return () => observer.disconnect();
  }, [chapters]);

  if (chapters.length === 0) return null;
  const safeIndex = Math.min(activeIndex, chapters.length - 1);

  // SSR and the hydration pass keep the dual mobile+desktop markup (CSS hides
  // the inactive side) to avoid a hydration mismatch; once mounted we swap to
  // rendering only the active variant so each visual mounts a single time.
  const showInlineVisuals = !hydrated || !desktop;
  const showStageVisual = !hydrated || desktop;

  const content = (
    <div className={cn("min-w-0 px-5 sm:px-10 lg:px-[clamp(2rem,6vw,7rem)]", contentClassName)}>
      {chapters.map((chapter, index) => (
        <article
          key={chapter.id}
          data-story-index={index}
          aria-current={index === safeIndex ? "step" : undefined}
          className={cn(
            "flex min-h-[72svh] flex-col justify-center border-b py-16 transition-opacity duration-300 motion-reduce:transition-none lg:min-h-svh",
            index === safeIndex ? "opacity-100" : "lg:opacity-40",
            chapterClassName,
          )}
        >
          {showInlineVisuals ? (
            <div
              role="img"
              aria-label={`${visualLabel}: ${chapter.title}`}
              className={cn(
                "relative mb-9 aspect-[4/3] overflow-hidden rounded-[1.5rem] bg-muted lg:hidden",
                visualClassName,
              )}
            >
              {renderVisual(chapter, index)}
            </div>
          ) : null}
          {chapter.eyebrow ? (
            <p className="text-xs font-semibold uppercase tracking-[0.18em] text-primary">
              {chapter.eyebrow}
            </p>
          ) : null}
          <h3 className="mt-3 text-3xl font-semibold tracking-tight sm:text-4xl">
            {chapter.title}
          </h3>
          <p className="mt-5 max-w-xl text-base leading-relaxed text-muted-foreground sm:text-lg">
            {chapter.body}
          </p>
        </article>
      ))}
    </div>
  );

  const visual = showStageVisual ? (
    <div
      className={cn("relative hidden h-svh min-w-0 lg:block", stageClassName)}
      style={{ position: "sticky", top: stickyTop }}
    >
      <div
        role="img"
        aria-label={visualLabel}
        className={cn("absolute inset-0 overflow-hidden bg-muted", visualClassName)}
      >
        {prefersReducedMotion ? (
          // Reduced motion: no crossfade stack, just an instant swap of the
          // active chapter's visual.
          <div className="absolute inset-0">
            {renderVisual(chapters[safeIndex], safeIndex)}
          </div>
        ) : (
          chapters.map((chapter, index) => (
            <div
              key={chapter.id}
              aria-hidden={index !== safeIndex}
              className={cn(
                "absolute inset-0 transition-[opacity,transform] duration-700 ease-out motion-reduce:transition-none",
                index === safeIndex ? "z-10 scale-100 opacity-100" : "z-0 scale-[1.015] opacity-0",
              )}
            >
              {renderVisual(chapter, index)}
            </div>
          ))
        )}
      </div>
    </div>
  ) : null;

  return (
    <section
      ref={rootRef}
      data-sticky-story
      data-experience-viewport={viewport}
      data-visual-side={visualSide}
      className={cn(
        "grid items-start gap-0 lg:grid-cols-[minmax(0,1fr)_minmax(22rem,1fr)]",
        className,
      )}
      {...props}
    >
      {visualSide === "left" ? <>{visual}{content}</> : <>{content}{visual}</>}
    </section>
  );
}

"use client";

import * as React from "react";

export const EXPERIENCE_BREAKPOINTS = {
  tablet: 640,
  desktop: 1025,
} as const;

export type ExperienceViewport = "mobile" | "tablet" | "desktop";

export type ExperienceResponsiveValue<T> = T | {
  /** Mobile-first value, also used during SSR/hydration. */
  mobile: T;
  /** iPad/tablet value. Falls back to `mobile` when omitted. */
  tablet?: T;
  /** Wide-screen value. Falls back to `tablet`, then `mobile`. */
  desktop?: T;
};

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

/**
 * Shared mobile-first viewport contract for every experience primitive.
 *
 * Mobile: < 640px · tablet/iPad: 640–1024px · desktop: >= 1025px.
 * Pointer capability remains a separate signal because an iPad can gain a
 * trackpad without changing its layout profile.
 */
export function useExperienceViewport(): ExperienceViewport {
  const tablet = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.tablet}px)`);
  const desktop = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.desktop}px)`);
  if (desktop) return "desktop";
  if (tablet) return "tablet";
  return "mobile";
}

export function resolveExperienceValue<T>(
  value: ExperienceResponsiveValue<T>,
  viewport: ExperienceViewport,
): T {
  if (typeof value !== "object" || value === null || !("mobile" in value)) return value;
  if (viewport === "desktop") return value.desktop ?? value.tablet ?? value.mobile;
  if (viewport === "tablet") return value.tablet ?? value.mobile;
  return value.mobile;
}

/** Conservative raster/WebGL supersampling budget for each layout profile. */
export function getExperienceDprCap(width: number) {
  if (width < EXPERIENCE_BREAKPOINTS.tablet) return 1;
  if (width < EXPERIENCE_BREAKPOINTS.desktop) return 1.25;
  return 1.6;
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}
